// Convert Gmail Trigger output to the {senderEmail, senderName, subject, body}
// shape that the rest of the workflow consumes (same as Sample email).
const item = $input.first().json;

const fromHeader = item.From || item.from || (item.headers && item.headers.from) || '';
const subject    = item.Subject || item.subject || (item.headers && item.headers.subject) || '';
const body       = item.text || item.body || item.snippet || '';

// Parse "Display Name <addr@example.com>" or just "addr@example.com"
const m = fromHeader.match(/^(.*?)\s*<(.+?)>\s*$/);
const senderName  = m ? m[1].replace(/^"|"$/g, '').trim() : '';
const senderEmail = m ? m[2].trim() : fromHeader.trim();

return [{ json: {
  senderEmail,
  senderName: senderName || senderEmail,
  subject,
  body,
} }];

