// AI Agent + Structured Output Parser puts the parsed verdict
// in $json.output. We re-attach the customer + email context so
// downstream nodes (case creation, communication, agent assignment)
// can keep using the existing references.
let verdict = $input.first().json.output ?? $input.first().json;
if (typeof verdict === 'string') verdict = JSON.parse(verdict);

const lookup = $('Lookup customer').first().json;
const customer = lookup?.customerId ? lookup : $('Create customer').first().json;
const email = $('Email source').first().json;

return [{ json: { ...verdict, customer, email } }];

